-- ============================================================
-- Booklesss — Strategic Management step content seed
-- Run in Supabase SQL Editor AFTER seed_lessons_steps.sql.
--
-- Populates the `content` JSONB for all 7 built Strategic Management
-- steps, transcribed from the ReportLab build scripts in
-- Schools/ZCAS/Strategic Management/*/sources/build_sm_*.py (the source
-- of truth per CLAUDE.md — all text lives directly in the script).
--
-- Tables from the PDFs are folded into readable prose in `body` since the
-- StepContent JSON schema (platform/lib/types.ts) has no table type.
-- Inline PDF markup (<b>, <i>, <br/>) is stripped since LessonContent.tsx
-- renders section body as plain text, not HTML.
-- ============================================================

update steps set content = '{"sections": [{"eyebrow": "CONCEPT 01", "heading": "What Is Corporate Strategy?", "body": "Strategy is the direction and scope of an organisation over the long-term, achieving advantage through its configuration of resources and competencies (Johnson, Scholes and Whittington). It is not operations — strategy sets where the business is going; operations execute that direction day to day.", "callout": {"label": "Fact", "body": "Strategy answers three questions: Where are we now? Where do we want to go? How do we get there? Every framework in this course maps onto one of these three."}}, {"eyebrow": "CONCEPT 02", "heading": "The Three Levels of Strategy", "body": "Strategy operates at three levels. Identifying which level a decision belongs to is a core exam skill — case questions frequently ask you to classify and explain.\n\nCorporate level: which industries and markets to compete in, portfolio decisions, capital allocation across units. Example: Zambeef expands cold-chain operations into East Africa alongside its Zambian business.\n\nBusiness (competitive) level: how to compete within a specific market, which customers to serve, how to beat rivals. Example: Zambeef retail competes on freshness and convenience rather than undercutting market stalls on price.\n\nFunctional/operational level: day-to-day implementation through HR, marketing, finance, and operations. Example: Zambeef marketing allocates ZMW 80,000 to a loyalty scheme for repeat customers.", "callout": {"label": "Exam Tip", "body": "Corporate = ''what businesses should we be in?'' Business = ''how do we compete in this business?'' Functional = ''how do we execute that strategy day to day?'' Classify the level before analysing the decision — that''s what the question is testing."}}, {"eyebrow": "CONCEPT 03", "heading": "Mintzberg''s Five Ps of Strategy", "body": "Mintzberg argued strategy is not always deliberate. He identified five forms it takes.\n\nPlan: a conscious, top-down process — analyse, choose, implement. The formal written strategy.\n\nPloy: a tactical manoeuvre against a specific rival. Not the long-run position — just the move.\n\nPattern: consistent behaviour that emerges over time, planned or not. Strategy as what you repeatedly do.\n\nPosition: how the firm places itself relative to competitors and the external environment.\n\nPerspective: the organisation''s ingrained worldview — its shared assumptions about how to compete.", "callout": {"label": "Exam Tip", "body": "Plan vs. Pattern is the most tested pair. Plan is deliberate and top-down. Pattern is emergent — it shows up in consistent decisions over time whether or not anyone planned it. A company can have an emergent pattern that contradicts its written plan."}}, {"eyebrow": "CONCEPT 04", "heading": "The Strategic Management Process", "body": "Strategic management is a cycle of four stages. Know each by name — ''describe the process'' is a standard long-answer question.\n\n1. Environmental Analysis — scan external threats and opportunities; audit internal resources and capabilities. Tools: PESTEL, Porter''s Five Forces (Step 2.1), SWOT, VRIO (Step 2.2).\n\n2. Strategy Formulation — set mission and objectives; generate strategic options; choose direction. Tools: Ansoff, BCG, Generic Strategies (Step 3.1, Step 3.2).\n\n3. Strategy Implementation — convert chosen strategy into structures, budgets, processes, and people.\n\n4. Evaluation and Control — monitor performance against targets; feed findings back into the next planning cycle.\n\nFormulation begins with purpose — what is this organisation for and what is it trying to achieve? Get that wrong and every option you evaluate will be measured against the wrong target. Mission, vision, and objectives are the starting point."}, {"eyebrow": "CONCEPT 05", "heading": "Competitive Advantage and Generic Strategies", "body": "A competitive advantage is an attribute that allows a firm to outperform rivals — through lower cost or higher perceived value. It is sustainable when rivals cannot easily replicate it. Porter mapped five specific approaches.\n\nLow-cost provider (broad scope): lowest industry cost base, compete on price.\n\nFocused low-cost (narrow scope): lowest cost within one specific niche.\n\nBroad differentiation (broad scope): distinctive product — quality, brand, innovation — at a premium price.\n\nFocused differentiation (narrow scope): unique features for a narrow customer group at a premium price.\n\nBest-cost provider (value buyers): good quality at a competitive price — the middle ground.", "callout": {"label": "Exam Tip", "body": "Scope — broad vs. narrow — is independent of cost vs. differentiation. When reading a case: identify the scope first, then identify the source of advantage. Mixing these up is the most common error in generic strategy questions."}}], "discussionQuestions": ["ZESCO announces it will expand into solar energy generation for rural communities. Identify which level of strategy this represents and justify your answer. Then name two decisions that must follow at the business level and two at the functional level to make the corporate decision viable.", "Zanaco operates branches across Zambia including rural areas that run at a loss. The bank treats this as part of its identity rather than a profitability question. Using Porter''s five generic strategies, identify which strategy Zanaco follows and explain your reasoning. Then identify one specific threat from a mobile money competitor and name the stage of the strategic management process where Zanaco should address it."], "keyTerms": [{"term": "Strategy", "definition": "Direction and scope of an organisation over the long-term, achieving advantage through resource configuration"}, {"term": "Corporate Level", "definition": "Decisions about which industries and markets to compete in; portfolio allocation across business units"}, {"term": "Business Level", "definition": "How to compete within a specific business unit or market"}, {"term": "Functional Level", "definition": "Day-to-day implementation of strategy through operational functions"}, {"term": "Mintzberg''s Five Ps", "definition": "Plan, Ploy, Pattern, Position, Perspective — five ways strategy forms in organisations"}, {"term": "Emergent Strategy", "definition": "A pattern in decisions that arises over time without a deliberate plan (Mintzberg''s Pattern)"}, {"term": "Competitive Advantage", "definition": "An attribute enabling a firm to outperform rivals through lower cost or higher value"}, {"term": "Porter''s Generic Strategies", "definition": "Five approaches: low-cost provider, focused low-cost, broad differentiation, focused differentiation, best-cost provider"}], "learningOutcomes": ["Define strategy using Johnson, Scholes and Whittington''s definition and state the three strategic questions it answers", "Classify any strategic decision as corporate, business, or functional level and justify the classification", "Name and define all five of Mintzberg''s Ps and distinguish deliberate (Plan) from emergent (Pattern) strategy", "Describe the four stages of the strategic management process in sequence", "Identify which of Porter''s five generic strategies a firm is using from a case description, separating scope from source of advantage"]}'::jsonb
where slug = 'intro-to-strategy'
  and lesson_id = (select id from lessons where slug = 'foundations' and course_id = (select id from courses where slug = 'strategic-management'));

update steps set content = '{"sections": [{"eyebrow": "CONCEPT 01", "heading": "The Four Components of Organisational Direction", "body": "Before executing strategy, every organisation must establish direction. Four components work together — each answers a different question and none substitutes for the others.\n\nStrategic Vision — where are we going and why? Long-term future.\n\nMission Statement — what do we do right now, and for whom? Present day.\n\nCore Values — what principles govern how we behave? Ongoing.\n\nObjectives — what specific results must we achieve? Short and long-term."}, {"eyebrow": "CONCEPT 02", "heading": "Strategic Vision", "body": "A strategic vision describes management''s aspirations for the company''s future and the course charted to achieve them. It answers where are we going? — not what the company does today.\n\nA good vision is specific enough to guide resource allocation decisions, forward-looking (not a description of current operations), feasible, and short enough to be memorable. Generic superlatives — ''be the best'', ''lead the industry'' — tell no one where to go.", "callout": {"label": "Fact", "body": "Exam test: does the statement describe a future destination with enough specificity to guide decisions? If it could belong to any company in any industry, it has failed as a vision."}}, {"eyebrow": "CONCEPT 03", "heading": "Mission Statement", "body": "The mission is grounded in the present. It answers what do we do, for whom, and how? A well-crafted mission identifies the products or services offered, the needs satisfied, the customer groups served, and what sets the organisation apart from rivals.\n\nVision vs. mission — the key distinction: vision covers the future state (where we are going), tested by whether it is forward-looking and specific enough to guide decisions. Mission covers the present state (why we exist today), tested by whether it describes current purpose, scope, and what sets the organisation apart.", "callout": {"label": "Exam Tip", "body": "The most common exam error: confusing vision and mission. A mission written in the future tense is probably a vision. A vision describing current operations is probably a mission. Pin each to its question before analysing it."}}, {"eyebrow": "CONCEPT 04", "heading": "Core Values", "body": "Core values are the beliefs and behavioural norms employees are expected to display in pursuing the firm''s vision and mission. When leadership genuinely models them, they become the reference point for decisions in situations where no rule exists. Values that conflict with strategy create internal contradiction — and values that leadership does not live destroy credibility faster than having none at all."}, {"eyebrow": "CONCEPT 05", "heading": "Setting Objectives", "body": "Objectives convert vision and mission into measurable targets. Without them, the vision has no way to track whether the organisation is moving toward it.\n\nFinancial objectives target revenue, profit, margins, return on investment, and cash flow — e.g. ZESCO targeting ZMW 2.4 billion revenue at an 18% operating margin by year-end. Strategic objectives target market position, customer relationships, and product capability — the non-financial drivers of future performance — e.g. ZESCO targeting 85% rural electrification coverage within five years.\n\nFinancial results are lagging indicators — they reflect decisions made months ago. Strategic objectives are leading indicators: winning on market standing and customer satisfaction today predicts financial performance tomorrow. Optimising only for financial targets at the cost of strategic ones is how companies post strong short-term results while eroding long-term position.\n\nWell-stated objectives meet four requirements: specific (precise enough that everyone agrees on what success looks like), measurable (a number or observable milestone, not a direction), challenging (ambitious enough to push performance, not so easy it creates complacency), and time-bound (a deadline, not an open-ended aspiration).\n\nStretch objectives push targets high enough to force creative thinking about how to achieve results, not just whether to aim for them. A company with strategic intent commits its full resources relentlessly to one ambitious long-term goal — it functions as an obsession that focuses the whole organisation.\n\nThe Balanced Scorecard prevents the failure of hitting financial targets while eroding the foundations that sustain them. It tracks performance across four perspectives: Financial (revenue, profit, ROI), Customer (market share, retention, satisfaction), Internal Processes (efficiency, quality, speed of delivery), and Learning and Growth (employee capability, technology, culture).", "callout": {"label": "Exam Tip", "body": "Why are financial objectives alone insufficient? Because they are lagging. The other three Balanced Scorecard perspectives show whether the organisation is building or eroding the capacity to perform financially in the future."}}], "discussionQuestions": ["Zanaco was originally established to extend banking to Zambians excluded from commercial banks. It has since grown into one of the country''s largest banks with retail, corporate, and mobile arms. Draft a one-sentence mission statement for Zanaco as it operates today. Then assess: ''To be the most trusted and accessible bank in Zambia'' — is this a vision, a mission, or neither? What is missing?", "First Quantum Minerals consistently meets annual financial targets — copper volume, revenue, and cost per tonne all on track. But it repeatedly misses strategic objectives on community investment, local supplier development, and environmental rehabilitation. Management says: ''the financials prove we are executing well.'' Using the theory from this step, explain what is actually happening and where this company is likely to be in ten years if the pattern continues."], "keyTerms": [{"term": "Strategic Vision", "definition": "Management''s aspirations for the company''s future and the course charted to achieve them — answers ''where are we going?''"}, {"term": "Mission Statement", "definition": "The company''s current purpose — what it does, for whom, and how — answers ''why do we exist today?''"}, {"term": "Core Values", "definition": "Beliefs and behavioural norms employees display in pursuing the firm''s vision and mission"}, {"term": "Objectives", "definition": "Specific, measurable performance targets that convert vision and mission into trackable results"}, {"term": "Financial Objectives", "definition": "Targets for revenue, profit, margins, and return on investment — lagging indicators"}, {"term": "Strategic Objectives", "definition": "Targets for market position, customers, and capability — leading indicators of future financial performance"}, {"term": "Stretch Objectives", "definition": "Targets set beyond current comfortable reach to push the organisation to its full potential"}, {"term": "Balanced Scorecard", "definition": "Framework tracking performance across financial, customer, internal processes, and learning and growth perspectives"}], "learningOutcomes": ["Name the four components of organisational direction and state the question each one answers", "Define strategic vision, state the requirements of an effective vision statement, and identify common pitfalls", "Distinguish precisely between vision and mission — what each answers and how each is tested in exams", "Distinguish financial from strategic objectives, explain why financial results are lagging indicators, and explain why both types are necessary", "Explain stretch objectives, strategic intent, and the purpose of the Balanced Scorecard"]}'::jsonb
where slug = 'mission-and-vision'
  and lesson_id = (select id from lessons where slug = 'foundations' and course_id = (select id from courses where slug = 'strategic-management'));

update steps set content = '{"sections": [{"eyebrow": "ORIENTATION", "heading": "Two Layers of the Outside World", "body": "Before choosing a strategy, an organisation must understand the environment it is competing in. That environment has two distinct layers — and analysing only one of them means planning in half the picture.\n\nMacro environment: broad forces that affect all industries — politics, economics, society, technology, ecology, law. No single company controls them. Primary tool: PESTEL Analysis.\n\nIndustry environment: the competitive structure of the specific market you operate in — who the rivals are, where the power sits, what threatens your position. Primary tool: Porter''s Five Forces.\n\nPESTEL answers: what forces are shaping the world we compete in? Porter''s Five Forces answers: what is the competitive structure of our specific industry? Neither replaces the other."}, {"eyebrow": "CONCEPT 01", "heading": "PESTEL Analysis", "body": "PESTEL maps the macro environment — the forces no single company controls but every company must respond to.\n\nPolitical: government stability, tax policy, trade regulations, foreign investment rules, state ownership requirements.\nEconomic: GDP growth, inflation, interest rates, exchange rates, employment levels, credit availability.\nSocial: demographics, urbanisation, education levels, cultural attitudes, consumer behaviour shifts.\nTechnological: digital infrastructure, automation, fintech disruption, mobile penetration, platform ecosystems.\nEnvironmental: climate risk, ecological regulations, sustainability requirements from investors and lenders.\nLegal: competition law, employment law, consumer protection, sector licensing and regulatory frameworks.\n\nPolitical decisions directly reset the rules of the game. When the Zambian government adjusted mining royalty rates in 2019 — raising them for open-cast mines to 9% at copper prices above USD 7,500 per tonne — First Quantum and other mining houses had to rebuild their investment cases overnight. No amount of internal efficiency offsets a policy change that moves the cost line by that magnitude.\n\nEconomic conditions set the baseline pressure on every business. Between 2015 and 2023, the kwacha depreciated from roughly K8 per USD to over K25. Any company holding USD-denominated debt or importing inputs in foreign currency absorbed that depreciation directly as a cost increase. Combined with inflation peaking above 22% in 2021, the economic environment forced constant revision of pricing, sourcing, and financing — not because of anything those companies did, but because of macro conditions they could not control.\n\nZambia''s population is young — over 60% are under 25 — and rapidly urbanising. That demographic profile drives demand for mobile-first products. Mobile money penetration has outpaced formal banking: MTN Mobile Money and Airtel Money collectively serve more Zambians than all commercial banks combined by transaction volume. A company that built its distribution strategy around physical branches in 2015 and failed to track this shift was positioned for the wrong market by 2022.", "callout": {"label": "Fact", "body": "Exam application: PESTEL is not a checklist to fill in — it is a thinking tool. The question is not ''what are the factors?'' but ''which factors are most material to this specific company in this specific context, and how do they interact?''"}}, {"eyebrow": "CONCEPT 02", "heading": "Porter''s Five Forces", "body": "PESTEL tells you about the world. Porter''s Five Forces tells you about the battlefield. The framework maps the competitive structure of an industry — where the power sits, what threatens margins, and whether an industry is structurally attractive or structurally difficult to profit in.\n\n1. Competitive Rivalry — the intensity of competition among existing players.\n2. Threat of New Entrants — how easily new competitors can enter the industry.\n3. Bargaining Power of Suppliers — how much leverage suppliers have over pricing and terms.\n4. Bargaining Power of Buyers — how much power customers have to demand lower prices or better terms.\n5. Threat of Substitutes — how easily customers can switch to a different product that serves the same underlying need.\n\nThe combined strength of all five forces determines how much of the value created in an industry firms can actually capture as profit. When forces are collectively strong — intense rivalry, easy entry, powerful buyers, powerful suppliers, credible substitutes — even well-run companies struggle to earn above-average returns.\n\nZambia''s commercial banking sector shows how two forces interact. Rivalry among existing banks — Zanaco, Standard Chartered, Absa, FNB, Stanbic — is intense; they compete for the same urban, salaried customer base with largely similar products, and switching costs are low. The Bank of Zambia requires K104 million in minimum paid-up capital for a commercial banking licence — a substantial barrier that protects incumbents from traditional new entrants. But Airtel and MTN did not enter as banks. They entered as mobile money operators under a different regulatory category, with their existing subscriber bases as instant distribution. The Five Forces framework only reveals this threat if you ask the right question: who can serve the same customer need by a different route?\n\nZambeef depends on ZESCO for the cold-chain electricity that keeps its processing plants and distribution network running. ZESCO is the sole provider of grid electricity — supplier power is extreme, and the company''s strategy must treat it as a structural constraint. Buyer power operates differently at different scales: an individual consumer buying Zambeef products from Shoprite has almost no bargaining power, but First Quantum sells copper concentrate to a small number of international smelters and trading houses who negotiate hard on pricing. Substitute threats are often the most misread force: mobile money is not a bank competitor, it is a substitute for the core function banking once monopolised — storing and transferring value.\n\nPESTEL and Porter''s Five Forces answer different questions, but the answers are connected. What they do not tell you is whether your organisation can actually respond to what it finds. That depends on what is inside — the capabilities, resources, and structure that either give it an edge or leave it exposed. Step 2.2 takes that up.", "callout": {"label": "Exam Tip", "body": "Key exam distinction: the threat of substitutes is NOT the same as competitive rivalry. Rivalry is between companies in the same industry (Zanaco vs. Absa). Substitution comes from a different category that serves the same underlying need (mobile money vs. a bank current account). A substitute can be more dangerous precisely because it arrives from outside the frame you are watching."}}], "discussionQuestions": ["Zambia Breweries is planning a major expansion of production capacity. Identify three PESTEL factors that would be most critical to this decision. For each one, explain why it is specifically material to a Zambian beverage manufacturer — not just to businesses in general.", "Airtel Money entered the Zambian market using its existing mobile subscriber base and a telecoms licence, bypassing the K104 million capital requirement for commercial banks. Which of Porter''s Five Forces did this strategy most directly exploit? What are the implications for established banks that defined their competitive landscape as ''other commercial banks''?"], "keyTerms": [{"term": "Macro environment", "definition": "The broad external forces — political, economic, social, technological, environmental, and legal — that affect all organisations and cannot be controlled by any single firm"}, {"term": "PESTEL Analysis", "definition": "A framework for scanning the macro environment across six categories: Political, Economic, Social, Technological, Environmental, and Legal"}, {"term": "Industry environment", "definition": "The competitive structure of the specific market an organisation operates in — shaped by rivals, potential entrants, suppliers, buyers, and substitutes"}, {"term": "Porter''s Five Forces", "definition": "A framework for analysing industry structure through five sources of competitive pressure: rivalry, new entrants, supplier power, buyer power, and substitutes"}, {"term": "Competitive Rivalry", "definition": "The intensity of competition among existing players in an industry"}, {"term": "Barriers to Entry", "definition": "Factors that make it costly or difficult for new competitors to enter an industry — capital requirements, regulation, brand loyalty, economies of scale"}, {"term": "Bargaining Power of Suppliers", "definition": "The ability of input suppliers to raise prices or restrict terms — strongest when suppliers are few and alternatives are limited"}, {"term": "Bargaining Power of Buyers", "definition": "The ability of customers to push down prices or demand better terms — strongest when buyers are large, concentrated, and face low switching costs"}, {"term": "Threat of Substitutes", "definition": "The risk that customers switch to a different product from a different category that serves the same underlying need"}], "learningOutcomes": ["Distinguish the macro environment from the industry environment and state the primary analytical tool for each", "Apply PESTEL Analysis to identify and assess the macro-environmental factors most material to a given organisation", "Name and define each of Porter''s Five Forces and explain how each affects industry profitability", "Explain the difference between competitive rivalry and the threat of substitutes, and illustrate with an example", "Use PESTEL and Porter''s Five Forces together to build a picture of the external environment a strategy must navigate"]}'::jsonb
where slug = 'external-environment'
  and lesson_id = (select id from lessons where slug = 'environment' and course_id = (select id from courses where slug = 'strategic-management'));

update steps set content = '{"sections": [{"eyebrow": "ORIENTATION", "heading": "Looking Inward After Looking Out", "body": "Step 2.1 mapped the external environment — the forces and competitive pressures that shape every industry. This step turns the lens inward. The same question applies, just from a different angle: given what the world looks like, what does your organisation actually have to work with?\n\nThree frameworks do this work together. SWOT surfaces strengths and weaknesses relative to the environment. Porter''s Value Chain shows where in the organisation value is created or lost. VRIO tests whether a specific resource or capability is genuinely a source of competitive advantage — or just something the company happens to have."}, {"eyebrow": "CONCEPT 01", "heading": "SWOT — The Internal Half", "body": "SWOT analysis covers both internal and external dimensions. Strengths and Weaknesses are internal — things the organisation controls. Opportunities and Threats are external — drawn from PESTEL and Porter''s Five Forces analysis. This step focuses on S and W.\n\nStrengths: resources, capabilities, and advantages that give the organisation an edge over rivals (internal). Weaknesses: gaps, limitations, and areas where the organisation underperforms relative to what the strategy requires (internal). Opportunities: favourable external conditions the organisation can exploit (external). Threats: adverse external conditions that could damage performance or competitive position (external).\n\nThe critical point about strengths and weaknesses: they are relative, not absolute. A strength is only meaningful if it matters in the current competitive environment. Zambeef''s vertically integrated cold chain — owning farms, abattoirs, cold storage, and retail outlets — is a genuine strength when supply chain reliability matters. But when ZESCO implements sustained load-shedding, that same integration becomes a vulnerability: every link in the chain depends on electricity that the company does not control. A strength in one environment can be a weakness in another.", "callout": {"label": "Fact", "body": "Exam test for SWOT: a strength must be relevant to the strategy and superior to what rivals have. If every competitor in the industry has the same capability, it is not a strength — it is the minimum requirement for competing."}}, {"eyebrow": "CONCEPT 02", "heading": "Porter''s Value Chain", "body": "Porter''s Value Chain breaks a company''s operations into the sequence of activities that create value for the customer. The analysis asks where in that sequence the company creates more value than it costs to produce — and where it does not.\n\nPrimary activities (direct): Inbound Logistics (receiving, storing, distributing inputs), Operations (transforming inputs into the finished product or service), Outbound Logistics (storing and distributing the finished product), Marketing & Sales (making customers aware of and willing to buy), Service (after-sale activities that maintain or enhance value).\n\nSupport activities (enabling): Procurement, Technology Development, Human Resources, Firm Infrastructure (finance, planning, legal, general management).\n\nThe value chain is most useful not as a description of what a company does, but as a diagnostic of where it wins or loses. Zambeef''s competitive position rests on its primary activities: inbound logistics (own farms supplying consistent quality inputs), operations (own abattoirs and processing), and outbound logistics (own cold-chain distribution fleet and retail outlets). A competitor sourcing from external suppliers and distributing through third-party retailers has less control at each link. That gap is where Zambeef''s advantage lives.\n\nSupport activities matter too. A company with strong HR management that retains skilled cold-chain technicians has a support advantage that is hard to see from the outside but very expensive to replicate. Technology development — how quickly a company can digitise its operations or adopt new processing equipment — determines how long any primary activity advantage actually lasts."}, {"eyebrow": "CONCEPT 03", "heading": "The VRIO Framework", "body": "SWOT and the value chain identify what a company has and where it operates. VRIO tests whether a specific resource or capability actually translates into competitive advantage — and if so, whether that advantage is sustainable. A resource is tested against four questions in sequence: is it Valuable? Is it Rare? Is it costly to Imitate? Is the firm Organised to exploit it?\n\nFails Value: competitive disadvantage — the resource destroys rather than creates value. Passes Value only: competitive parity — everyone has it; it''s the industry standard, not an edge. Passes Value and Rarity, fails Inimitable: temporary advantage — rivals can copy it; the lead erodes over time. Passes Value, Rarity and Inimitable, fails Organised: unrealised advantage — the capability exists but the company is not structured to exploit it. Passes all four: sustained competitive advantage — the source of above-average returns over time.\n\nFirst Quantum''s mineral rights and processing infrastructure at Kansanshi pass all four VRIO tests: valuable (copper production generates significant returns), rare (specific rights to that ore body are not available to others), inimitable (the capital cost and geological knowledge required to replicate it are enormous), and organised around exploiting it through dedicated operational systems and technical expertise. The result is a sustained competitive position that smaller miners in the same geography cannot match.\n\nMTN Zambia''s mobile money platform is valuable and rare — few organisations have 4 million registered users and the agent network to serve them. But it is becoming imitable: Airtel Money has built comparable scale, and the regulatory environment is opening mobile money to new entrants. Unless MTN deepens the inimitability, the advantage is temporary. VRIO forces you to ask not just ''do we have it?'' but ''how long will it hold?''\n\nSWOT, the value chain, and VRIO each answer part of the same question: what does this organisation bring to the competitive environment it faces? Together, they complete the picture that Step 2.1 started from the outside. Whether those internal capabilities are enough to pursue a specific strategic direction is the question Lesson 3 addresses.", "callout": {"label": "Exam Tip", "body": "Common exam error: treating all company resources as strengths. VRIO separates resources that genuinely create advantage from those that simply keep the company in the game. A bank that has ATMs across Lusaka has Value — but so does every other bank. It passes V, fails R. That is parity, not advantage."}}], "discussionQuestions": ["Zanaco is one of the few commercial banks in Zambia with a government ownership stake. In a SWOT analysis, is this a strength, a weakness, or both? Consider: what does it give the bank, what does it constrain, and under what conditions does it shift from one category to the other?", "MTN Zambia has built a mobile money platform with over 4 million registered users and one of the widest agent networks in the country. Apply the VRIO framework to this capability. Does it currently represent a sustained competitive advantage, a temporary advantage, or competitive parity? What would need to change — in the company or the environment — to shift your answer?"], "keyTerms": [{"term": "Internal environment", "definition": "The resources, capabilities, processes, and culture inside an organisation — the factors it controls and that determine what it can do"}, {"term": "SWOT Analysis", "definition": "A framework identifying internal Strengths and Weaknesses alongside external Opportunities and Threats"}, {"term": "Strength", "definition": "A resource or capability that gives the organisation a relative advantage over rivals in the current competitive environment"}, {"term": "Weakness", "definition": "A gap or limitation that puts the organisation at a disadvantage relative to what the strategy requires or what rivals can do"}, {"term": "Value Chain", "definition": "Porter''s framework mapping an organisation''s activities into the sequence that creates value — primary activities and support activities"}, {"term": "Primary Activities", "definition": "The five directly value-creating activities: inbound logistics, operations, outbound logistics, marketing and sales, and service"}, {"term": "Support Activities", "definition": "Activities that enable the primary activities: procurement, technology development, human resources, and firm infrastructure"}, {"term": "VRIO Framework", "definition": "A test of whether a resource creates sustained competitive advantage: Valuable, Rare, Inimitable, and Organised to exploit"}, {"term": "Sustained Competitive Advantage", "definition": "A position of above-average performance that persists because the underlying capability passes all four VRIO tests"}, {"term": "Core Competency", "definition": "A capability that is central to the firm''s strategy and performance, typically passing at least the V, R, and I tests of VRIO"}], "learningOutcomes": ["Distinguish the internal from the external dimensions of SWOT, and explain why strengths and weaknesses are relative rather than absolute", "Apply Porter''s Value Chain to identify where in an organisation''s activities value is created, and where advantage or weakness lies", "Apply the VRIO framework to a specific resource or capability and determine whether it represents competitive parity, temporary advantage, or sustained competitive advantage", "Explain why a resource that passes only the Value test is not a source of competitive advantage", "Use SWOT, the value chain, and VRIO together to build an integrated picture of an organisation''s internal strategic position"]}'::jsonb
where slug = 'internal-environment'
  and lesson_id = (select id from lessons where slug = 'environment' and course_id = (select id from courses where slug = 'strategic-management'));
update steps set content = '{"sections": [{"eyebrow": "ORIENTATION", "heading": "Where Strategy-Making Happens", "body": "In Lessons 1 and 2 you built the analytical foundation: you know what strategy is (Step 1.1), what the organisation stands for (Step 1.2), what external forces are at work (Step 2.1), and what the organisation is genuinely capable of (Step 2.2). Now the work shifts from analysis to choice.\n\nStrategic choices happen at three distinct levels. Each level answers a different question, involves different decision-makers, and operates on a different time horizon. Getting the levels confused is one of the most common strategy mistakes — corporate leadership meddling in operational decisions, or business units making portfolio choices that should sit with the board.\n\nCorporate level (Board / Group CEO, 5-10 years): which businesses should we be in, how do we allocate capital across them? Business level (Divisional MD / BU head, 2-5 years): how do we compete and win within our chosen market? Functional level (functional heads, 1-2 years): how does each function support the business strategy?\n\nThis step is about corporate-level strategy — the top of the hierarchy. It is the most consequential and the hardest to reverse. Entering a new industry or acquiring a business takes years to undo if it turns out to be wrong. That is why the analytical work of Lessons 1 and 2 must come first."}, {"eyebrow": "STRATEGIC CHOICE", "heading": "The Four Corporate-Level Strategy Directions", "body": "At the corporate level, the fundamental question is: what direction should this organisation move in? There are four broad directions, and every corporate-level decision fits into one of them.\n\nGrowth: expand into new products, markets, or businesses, increasing revenue and competitive scope. Choose it when the environment offers real opportunity and the firm has the capability and capital to capture it.\n\nStability: maintain the current position, protecting what works without significant new investment. Choose it when the market is mature, the firm is performing well, and disruption carries more risk than growth.\n\nRetrenchment: pull back — cut costs, exit underperforming businesses, refocus on core strengths. Choose it when performance is declining, resources are stretched, or parts of the portfolio are destroying value.\n\nCombination: apply different directions to different business units simultaneously. Choose it when the portfolio is diverse — some units merit growth investment, others stability or exit.\n\nMost large Zambian organisations are combination strategists without labelling it: Zambeef invests aggressively in cold-chain capacity (growth) while running its retail outlets as mature steady earners (stability). First Quantum Minerals expands into new minerals and geographies while exiting mines that no longer cover their cost of capital (retrenchment)."}, {"eyebrow": "GROWTH STRATEGIES", "heading": "How Organisations Expand: Four Paths", "body": "When an organisation chooses growth, it still needs to decide how to grow. The four main growth paths carry very different risk profiles and capability requirements.\n\n1. Concentrated Growth (Intensification): focus resources on profitable growth within the existing product in the existing market. Zambia''s mobile-money market used concentrated growth for years — MTN, Airtel, and Zamtel competed intensely for the same customer base before market saturation pushed them toward new segments.\n\n2. Market and Product Development: market development takes an existing product into a new market (e.g. Zambian Breweries expanding distribution into rural areas or neighbouring countries). Product development launches new products for existing customers (e.g. a bank launching insurance and pension products to its existing account holders). Both are lower-risk than full diversification because the firm leverages something it already knows well.\n\n3. Vertical Integration: expand along the supply chain, either backward (toward suppliers) or forward (toward customers). Zambeef''s ownership of its own feedlots, abattoirs, and processing plants is backward integration. A manufacturer opening its own retail outlets instead of selling through distributors is forward integration — the advantage is margin capture and direct customer relationships, the risk is that running retail requires very different capabilities than manufacturing.\n\n4. Horizontal Integration: acquire or merge with a competitor at the same stage of the value chain, for scale, market share, and elimination of a rival. Stanbic Bank''s acquisition of CFC Bank in Zambia is horizontal integration — same industry, same customer base, merged to achieve scale. The risk is that mergers are expensive to execute, and cultural clashes frequently destroy the value they were meant to create."}, {"eyebrow": "DIVERSIFICATION", "heading": "Moving Beyond the Core Business", "body": "Diversification means entering a business that is genuinely new to the firm — different products, different markets, different competitive dynamics. It is the highest-risk growth path, and the evidence from decades of research is humbling: most diversification moves destroy shareholder value. Yet done well, diversification can reduce risk by spreading income across businesses and create value when real synergies exist.\n\nRelated diversification (concentric): enter businesses that share technology, customers, distribution channels, or brand with the core business. The test is whether real synergies exist — not just the word ''synergy,'' but specific cost savings or revenue enhancements that would not exist if the businesses were separate. A Zambian bank entering asset management, insurance, or stockbroking is related diversification: same customers, complementary products, shared compliance infrastructure.\n\nUnrelated diversification (conglomerate): enter businesses with no strategic connection to the core. The only rationale is financial — the acquirer believes it can manage the business better than current owners, or that cash flows from different industries reduce overall risk. It is notoriously hard to execute: managing a mining company and a supermarket chain requires completely different capabilities. Most large conglomerates eventually break up because the parts are worth more separately than together.", "callout": {"label": "Fact", "body": "The three tests for any diversification: (1) Industry attractiveness — is the target industry genuinely attractive, or are you buying into a declining sector? (2) Cost of entry — will you pay so much to acquire that future profits can never justify the price? (3) Better-off test — will the combined entity be better off than the businesses operating independently?"}}, {"eyebrow": "PORTFOLIO ANALYSIS", "heading": "The BCG Matrix: Allocating Capital Across the Portfolio", "body": "When an organisation runs multiple businesses or product lines, it needs a way to decide where to invest, where to harvest, and where to exit. The BCG Growth-Share Matrix (developed by Boston Consulting Group) is the most widely used tool for this. It maps every business unit on two dimensions: market growth rate and relative market share.\n\nStars (high growth, high share): invest heavily to maintain position — Stars will become Cash Cows as the market matures. Cash flow is roughly neutral.\n\nCash Cows (low growth, high share): milk the profits — the market has matured but you still lead it. Don''t over-invest; extract cash to fund Stars and Question Marks. Cash flow is strongly positive — the engine of the portfolio.\n\nQuestion Marks (high growth, low share): decide quickly — invest to become a Star, or exit before the market matures and you''re stuck as a Dog. Cash flow is negative.\n\nDogs (low growth, low share): exit or reposition — low-growth, low-share businesses consume management attention and rarely justify their cost of capital. Cash flow is neutral to negative — often better to divest.\n\nApplying a rough BCG lens to Zambian Breweries (part of AB InBev): Mosi Lager, the dominant mass-market beer with high share in a mature market, is a classic Cash Cow — the company''s earnings engine. Eagle Lager and Rhino Lager, affordable sorghum-based beers targeting lower-income consumers, sit somewhere between Cash Cow and Star depending on growth trends in that segment. Premium imported brands the company distributes are Question Marks — the company must decide whether to invest seriously in premium positioning or leave that segment to independents.", "callout": {"label": "Limitation", "body": "The matrix assumes that market share drives profitability (via experience curve effects) and that high-growth markets are always worth entering. Neither is universally true. Use BCG as a starting framework, not a formula — the three diversification tests still apply."}}], "discussionQuestions": ["Zambeef operates beef, chicken, fish, retail (Zambeef shops), and cold-chain logistics. Is this related or unrelated diversification? What synergies exist? Which parts of the portfolio do you think pass the three diversification tests — and which might not?", "Pick a Zambian organisation with multiple products or business units (Zambeef, Zanaco, MTN Zambia, ZESCO, or any other). Map its major units onto the BCG Matrix. Based on your analysis: where should capital be allocated, where should it be harvested, and is there anything that should be exited?"], "keyTerms": [{"term": "Corporate strategy", "definition": "The top-level decisions about which businesses an organisation is in and how capital is allocated across them"}, {"term": "Business strategy", "definition": "How a single business unit competes and wins within its chosen market"}, {"term": "Functional strategy", "definition": "How individual functions (finance, marketing, operations) support the business strategy"}, {"term": "Growth strategy", "definition": "A corporate direction that seeks to expand revenue, scope, or market position"}, {"term": "Stability strategy", "definition": "Maintaining the current position without significant new investment or expansion"}, {"term": "Retrenchment strategy", "definition": "Pulling back — reducing scope, cutting costs, or exiting underperforming businesses"}, {"term": "Concentrated growth", "definition": "Growing by deepening penetration of the existing product in the existing market"}, {"term": "Vertical integration", "definition": "Expanding along the supply chain — backward toward suppliers or forward toward customers"}, {"term": "Horizontal integration", "definition": "Acquiring or merging with a competitor at the same stage of the value chain"}, {"term": "Related diversification", "definition": "Entering new businesses that share technology, customers, or channels with the core"}, {"term": "Unrelated diversification", "definition": "Entering businesses with no strategic connection to the core — pure financial rationale"}, {"term": "BCG Matrix", "definition": "A portfolio tool that maps business units by market growth rate and relative market share"}, {"term": "Cash Cow", "definition": "High-share, low-growth unit — generates cash but needs minimal reinvestment"}, {"term": "Star", "definition": "High-share, high-growth unit — invest to maintain; will become Cash Cow as market matures"}, {"term": "Question Mark", "definition": "Low-share, high-growth unit — invest to win or exit before the market matures"}, {"term": "Dog", "definition": "Low-share, low-growth unit — exit or reposition; rarely worth continued investment"}], "learningOutcomes": ["Explain the three levels of strategy and identify which decisions belong at each level", "Describe the four corporate strategy directions and the conditions that favour each", "Distinguish between the four growth paths — concentration, integration, market development, and diversification", "Apply the three diversification tests to evaluate whether a new business makes strategic sense", "Use the BCG Matrix to analyse a multi-business portfolio and make capital allocation recommendations"]}'::jsonb
where slug = 'corporate-strategy'
  and lesson_id = (select id from lessons where slug = 'strategy' and course_id = (select id from courses where slug = 'strategic-management'));

update steps set content = '{"sections": [{"eyebrow": "ORIENTATION", "heading": "From Portfolio to Battlefield", "body": "Step 3.1 answered the corporate question: which businesses should we be in? This step answers the business-level question: how do we compete and win in the business we have chosen? The difference matters. A wrong corporate decision wastes years; a wrong competitive decision wastes resources and market position that are hard to recover.\n\nMichael Porter''s core argument is that sustainable competitive advantage comes from choosing a clear position — and that the worst strategic error is trying to be everything to everyone. He calls this being ''stuck in the middle'': neither cost-competitive nor meaningfully differentiated. Stuck-in-the-middle firms earn below-average returns across every industry."}, {"eyebrow": "COMPETITIVE POSITION", "heading": "Porter''s Three Generic Strategies", "body": "Porter identifies three viable strategic positions. Two dimensions define the space: the source of advantage (lower cost vs unique value) and the competitive scope (broad market vs narrow segment).\n\nCost Leadership (broad market): produce and deliver at lower cost than anyone else, passing some savings to customers while keeping the rest as margin. Core risk: technology change erodes your cost advantage overnight, and rivals copy your efficiencies.\n\nDifferentiation (broad market): offer something competitors cannot easily replicate — brand, technology, service, design — and charge a premium. Core risk: the premium narrows as competitors imitate, or customer preferences shift away from your differentiator.\n\nCost Focus (narrow segment): be the low-cost provider for a specific customer group, geography, or product niche. Core risk: the segment may shrink or lose attractiveness, and broad cost leaders may attack it.\n\nDifferentiation Focus (narrow segment): serve a specific segment so well that broader competitors cannot match you in that niche. Core risk: broad differentiators may narrow their focus, or segment needs may drift toward mainstream.\n\nShoprite and Pick n Pay compete on cost leadership in Zambian retail — scale buying, efficient logistics, no-frills store formats. A local chain that tries to match their prices without their scale is on a losing path; the correct response is to differentiate or focus instead.\n\nZanaco''s business banking offering differentiates through local relationships, Zambia-specific products, and access to government contracting networks — areas where an international bank cannot easily match. Zambeef differentiates on vertical integration (farm-to-shelf traceability) and cold-chain reliability, which smaller competitors cannot afford to replicate.", "callout": {"label": "Stuck in the Middle", "body": "A Zambian supermarket that tries to match Shoprite''s prices AND offer premium imported goods AND compete on convenient locations simultaneously will be worse than Shoprite at cost, worse than specialty retailers at range, and worse at everything else. Pick one position and make it defensible."}}, {"eyebrow": "EXECUTION", "heading": "Achieving and Defending Each Position", "body": "Cost leadership is not just about cutting prices — it is about structural cost advantages built into how the business operates: scale (higher volume spreads fixed costs over more units — Zambia''s telecom operators), the experience curve (cumulative production lowers unit costs over time), process design (standardised, efficient workflows reduce labour and waste), supply chain (preferred supplier contracts, bulk purchasing, backward integration), and technology (automation of routine tasks, digital delivery instead of physical).\n\nDifferentiation must be perceived as valuable by customers AND hard for competitors to copy — differences that customers don''t notice or don''t care about are irrelevant. It is built through brand (built over years, impossible to copy quickly — MTN''s brand in Zambia), proprietary technology or process, customer relationships and switching costs, quality signals (certifications, awards, reputation), and integration depth (like Zambeef''s farm-to-retail chain)."}, {"eyebrow": "COMPETITIVE MOVES", "heading": "Offensive Strategies: Going on the Attack", "body": "Once a firm has a competitive position, the question becomes: how do you strengthen it? Offensive strategies are deliberate moves to improve competitive position, gain market share, or neutralise a rival''s advantage. They are not random — each has a specific objective and a specific counter-risk.\n\nAttack competitor strengths: match or exceed rivals in their area of advantage — out-invest, out-innovate, undercut on price. Use when you have resources to sustain the fight and the long-term prize justifies the cost.\n\nAttack competitor weaknesses: target gaps — underserved segments, slow distribution, weak customer service. Use when rivals are overextended or have neglected specific segments or regions.\n\nEnd-run (blue ocean): bypass existing competition entirely by creating a new market space where rivals don''t yet compete. Use when existing markets are saturated and there is a genuinely underserved need.\n\nGuerrilla offensives: small, targeted strikes — price promotions in specific regions, aggressive local marketing — to disrupt rather than defeat. Use when the firm lacks scale for a direct assault but can inflict damage selectively and cheaply.\n\nPre-emptive strikes: lock up resources, talent, or partnerships before rivals can. Use when a new opportunity is emerging and being first creates durable lock-in.", "callout": {"label": "Fact", "body": "First-mover advantages in Zambia: M-Pesa (now Airtel Money predecessor) entered mobile money early and built a customer base that later entrants struggled to displace. Network effects made it self-reinforcing — the more users, the more useful. Late entrants had to spend heavily on incentives just to reach parity."}}, {"eyebrow": "PROTECTING POSITION", "heading": "Defensive Strategies: Holding Your Ground", "body": "Competitive advantage is never permanent. Rivals attack, technology shifts, regulations change, and consumer preferences evolve. Defensive strategy is about making your position harder to attack and responding to threats before they erode your standing.\n\nRaising barriers to attack: switching costs (loyalty programmes, data lock-in, long contracts), broadening the product range to fill gaps rivals could exploit, exclusive supplier or distribution agreements, and signalling strength to deter opportunistic entry.\n\nResponding to an attack: the correct response depends on the nature of the attack. If a rival is attacking your core customer segment with lower prices, the question is not ''match the price'' but ''why are customers defecting, and can we fix that without destroying margin?'' A targeted response — price-matching only in the attacked segment, not market-wide — is cheaper and sends a signal without collapsing the entire pricing structure.", "callout": {"label": "Defensive Principle", "body": "The goal is not to respond to every attack but to make your position structurally unattractive to attack. If rivals know you will defend aggressively and have the resources to do so, they will often look elsewhere. The best defence is building genuine advantages that competitors cannot easily replicate."}}], "discussionQuestions": ["Think about an industry in Zambia where the competitive dynamics have shifted in the past five years — banking, telecom, retail, or fast food. What offensive moves triggered those shifts? Which companies responded well, and which were caught out? What does this tell you about the importance of monitoring rivals?", "You are the Strategy Director of a mid-sized Zambian bank. A new digital-only competitor has launched with zero-fee accounts and instant mobile onboarding. Your bank currently leads on branch network and business banking relationships. What competitive strategy do you adopt — and what specific defensive or offensive moves do you make in the next 12 months?"], "keyTerms": [{"term": "Competitive strategy", "definition": "The approach a business takes to compete and win within its chosen market"}, {"term": "Cost leadership", "definition": "Competing by being the lowest-cost producer in the industry while maintaining acceptable quality"}, {"term": "Differentiation", "definition": "Competing by offering unique value that customers prize and are willing to pay a premium for"}, {"term": "Focus strategy", "definition": "Competing by dominating a narrow market segment with either cost or differentiation advantage"}, {"term": "Stuck in the middle", "definition": "The losing position of firms that pursue neither cost leadership nor meaningful differentiation"}, {"term": "Competitive scope", "definition": "The breadth of the market a firm targets — broad (whole industry) or narrow (specific segment)"}, {"term": "Offensive strategy", "definition": "Deliberate moves to strengthen competitive position, gain share, or erode a rival''s advantage"}, {"term": "Defensive strategy", "definition": "Actions taken to protect competitive position from attack and make it structurally unattractive for rivals"}, {"term": "First-mover advantage", "definition": "Benefits gained by entering a market before competitors — brand, customer lock-in, standard-setting"}, {"term": "Switching costs", "definition": "The cost (financial, operational, psychological) of moving from one supplier to another — a key defensive barrier"}, {"term": "Experience curve", "definition": "The systematic decline in unit costs as cumulative production increases, due to learning and efficiency gains"}, {"term": "Competitive dynamics", "definition": "The ongoing cycle of offensive moves, defensive responses, and counter-moves between rivals"}], "learningOutcomes": ["Explain Porter''s three generic strategies and the logic behind each", "Identify firms stuck in the middle and explain why that position underperforms", "Describe how to build and defend cost leadership and differentiation positions", "Distinguish between offensive strategic moves and know when each is appropriate", "Design a defensive response to a competitive attack while protecting core margins"]}'::jsonb
where slug = 'competitive-strategy'
  and lesson_id = (select id from lessons where slug = 'strategy' and course_id = (select id from courses where slug = 'strategic-management'));

update steps set content = '{"sections": [{"eyebrow": "ORIENTATION", "heading": "The Execution Problem", "body": "You have completed the analytical and strategic choice phases: you understand the environment (Steps 2.1-2.2), you have made portfolio decisions (Step 3.1), and you have chosen a competitive position (Step 3.2). None of that matters until it is translated into action.\n\nMcKinsey research shows that fewer than one in three strategically important initiatives is executed as planned. The root causes are almost never the strategy itself — they are execution failures: misaligned structures, wrong metrics, change resistance, and resources not matching priorities. This step is about preventing those failures.", "callout": {"label": "Strategic Control", "body": "Implementation is not a one-off event. It requires ongoing monitoring, comparison against targets, and willingness to adapt when the plan meets reality. Strategy without control drifts. Control without strategy optimises for the wrong outcomes."}}, {"eyebrow": "ALIGNMENT", "heading": "The McKinsey 7-S Framework", "body": "The McKinsey 7-S Framework identifies seven internal elements that must point in the same direction for strategy to succeed. If even one is misaligned, execution suffers.\n\nStrategy: the direction and choices the organisation is pursuing — is it clear, specific, and understood at every level?\nStructure: how authority, accountability, and decision-making are organised — does it enable strategy or create barriers?\nSystems: processes, budgets, information flows, measurement — do they measure and reward behaviours the strategy requires?\nStyle: leadership approach and cultural tone from the top — does leadership model the behaviour the strategy asks for?\nStaff: people — hiring, development, talent pipeline — do we have the right people in the roles the strategy depends on?\nSkills: distinctive capabilities and organisational competencies — what does the strategy require, and where are the gaps?\nShared Values: core purpose and culture, the centre of the model — do people believe in what the organisation stands for?\n\nZambian example: a Zambian bank pursues a digital-first strategy to reach unbanked customers via mobile. Strategy is clear. But the branch structure remains hierarchical with decisions made centrally in Lusaka (Structure misaligned). Technology hiring is constrained by grade-band pay structures designed for branch roles (Staff misaligned). Performance bonuses still reward in-branch transactions, not mobile onboarding (Systems misaligned). This strategy will fail — not because the idea is wrong, but because six of the seven elements are pulling against it."}, {"eyebrow": "MEASUREMENT", "heading": "The Balanced Scorecard", "body": "Strategy is a hypothesis: if we do X, then Y will result. The Balanced Scorecard translates that hypothesis into measurable targets across four perspectives, making it possible to monitor whether the strategy is actually working — and to intervene before financial results deteriorate.\n\nFinancial — is the strategy delivering financial returns? Measure: revenue growth, profit margin, cash flow, ROI on strategic initiatives.\nCustomer — are target customers satisfied and loyal? Measure: satisfaction score, retention rate, market share in target segment.\nInternal Process — are we executing critical processes efficiently? Measure: process cycle time, quality defect rate, speed of key workflows.\nLearning & Growth — are we building the capabilities the strategy requires? Measure: employee capability index, training hours, rate of innovation.\n\nThe power of the Balanced Scorecard is the cause-and-effect chain: invest in Learning & Growth (train people) leads to improved Internal Processes (serve faster, with fewer errors) leads to improved Customer outcomes (higher satisfaction, lower churn) leads to improved Financial results. Without this chain, a company can hit its financial targets by destroying the capabilities that will generate next year''s results.\n\nA Zambian telecommunications company pursuing customer retention might measure: Financial — ZMW revenue per subscriber and churn cost avoided; Customer — Net Promoter Score and complaint resolution rate; Internal Process — time-to-resolve a service fault; Learning & Growth — percentage of frontline staff trained on new systems. These four numbers, reviewed monthly, tell a more complete strategic story than revenue alone."}, {"eyebrow": "PEOPLE", "heading": "Change Management: The Human Side of Strategy", "body": "Strategy is not just about systems and structure — it is fundamentally about people changing their behaviour. If the organisation has worked one way for years, a new strategy requires breaking old patterns and building new ones. This is where most implementation efforts fail: people resist change, especially when they don''t understand why it is necessary.\n\nJohn Kotter''s research identifies the sequence that separates successful transformations from failures:\n1. Establish urgency — make a clear, compelling case for why change is necessary now. Skip it, and inertia wins.\n2. Build a coalition — recruit powerful sponsors who believe in the change. Skip it, and isolated advocates cannot overcome systemic scepticism.\n3. Form a vision — articulate a clear picture of what success looks like. Skip it, and people default to the past.\n4. Communicate constantly — repeat the vision through every channel available. Skip it, and the message gets lost.\n5. Remove barriers — give people permission and resources to act on the vision. Skip it, and bureaucracy blocks change.\n6. Create early wins — identify and celebrate quick, visible victories. Skip it, and momentum dies.\n7. Build on wins — keep pressure on; avoid declaring victory prematurely. Skip it, and old habits resurface.\n8. Anchor the change — embed new behaviour in culture, systems, and hiring. Skip it, and change reverts under pressure.", "callout": {"label": "Fact", "body": "Budget and time estimates for strategy implementation should include 30-40% effort on change management. If you are not investing in getting people to change behaviour, the strategy has no chance of landing."}}, {"eyebrow": "DESIGN", "heading": "Structure Follows Strategy", "body": "Chandler''s principle — that structure should follow strategy — sounds obvious but is violated constantly. Organisations redesign their strategy and then try to execute it with structures built for a different purpose. The result is friction: decisions made in the wrong place, accountability diffused, coordination failures.\n\nFunctional structure (grouped by Finance, Sales, Operations, HR): best fit for cost leadership, operational efficiency, and stability strategies. Key risk: silos create coordination failures across functions.\nDivisional structure (grouped by product, geography, or customer segment): best fit for growth, diversification, and multi-market strategy. Key risk: duplication of functions increases cost.\nMatrix structure (dual reporting — functional and divisional lines): best fit for innovation, customisation, and complex projects. Key risk: conflict over authority and confusion about decisions.\nNetwork structure (loosely coupled units, heavy outsourcing, partnerships): best fit for agility, specialisation, and platform strategies. Key risk: loss of control, consistency and quality risks.\n\nA Zambian fintech startup pursuing cost leadership in digital payments suits a functional structure — centralised technology development, lean operations, minimum overhead. A pharmaceutical company with multiple product categories suits divisional structure so each category can pursue its own market approach. The first sign that structure and strategy are misaligned: decisions keep escalating to levels that shouldn''t need to make them."}, {"eyebrow": "CONTROL", "heading": "Strategic Control: Monitoring and Adapting", "body": "Strategy implementation is not a project with a completion date — it is an ongoing process of monitoring, comparing actuals to targets, diagnosing gaps, and adapting. Strategic control is distinct from operational control: operational control asks ''are we executing efficiently?'' — strategic control asks ''is the strategy itself still valid?''\n\nPremise control: monitor the assumptions behind the strategy. If the PESTEL factors that justified the strategy change materially, the strategy may need revision.\nImplementation control: track whether milestones are being hit and whether resources are being deployed as planned.\nStrategic surveillance: broad monitoring of the competitive environment for unexpected developments.\nSpecial alert control: pre-defined response protocols for sudden crises — a competitor acquisition, a regulatory change, a supply disruption."}], "discussionQuestions": ["A large Zambian parastatal (ZESCO, Zambia Railways, or similar) has just appointed a new CEO with a mandate to transform the organisation. Using the McKinsey 7-S framework, identify the three elements most likely to resist change and explain why. What would Kotter''s model say should happen in the first 90 days?", "You are a senior manager at First Quantum Minerals'' Kansanshi copper mine during a period of falling global copper prices. The corporate strategy set two years ago assumed a copper price of USD 8,500 per tonne. The current price is USD 6,200. Walk through the four types of strategic control: what specific actions does each type require? At what price level would you trigger a fundamental strategy review — and what would that review examine?"], "keyTerms": [{"term": "Strategy implementation", "definition": "The process of translating strategic choices into action through structure, systems, people, and resources"}, {"term": "McKinsey 7-S", "definition": "A framework identifying seven elements that must align for strategy to succeed: Strategy, Structure, Systems, Style, Staff, Skills, Shared Values"}, {"term": "Balanced Scorecard", "definition": "A measurement system that tracks performance across four perspectives: Financial, Customer, Internal Process, and Learning & Growth"}, {"term": "Change management", "definition": "The structured approach to transitioning people, teams, and organisations from a current state to a desired future state"}, {"term": "Kotter''s 8-Step Model", "definition": "A change management sequence: urgency, coalition, vision, communication, empowerment, early wins, consolidation, anchoring"}, {"term": "Strategic control", "definition": "Ongoing monitoring of whether the strategy is being implemented correctly and whether its underlying assumptions remain valid"}, {"term": "Premise control", "definition": "Monitoring the environmental assumptions that justified the strategy — if assumptions change, the strategy may need revision"}, {"term": "Functional structure", "definition": "Organisation grouped by function (finance, marketing, operations) — suited to cost leadership and efficiency strategies"}, {"term": "Divisional structure", "definition": "Organisation grouped by product, geography, or customer segment — suited to diversification and multi-market strategies"}, {"term": "Structure follows strategy", "definition": "Chandler''s principle: organisational structure should be designed to enable execution of the chosen strategy, not the other way around"}, {"term": "Leading indicator", "definition": "A metric that predicts future performance (e.g. training completion predicts future process quality)"}, {"term": "Lagging indicator", "definition": "A metric that reflects past performance (e.g. profit margin reflects decisions made months earlier)"}], "learningOutcomes": ["Apply the McKinsey 7-S framework to diagnose alignment gaps in an organisation''s strategy implementation", "Build a Balanced Scorecard with relevant KPIs across all four perspectives for a given strategic objective", "Describe Kotter''s 8-step change model and explain the cost of skipping any step", "Match organisational structures to strategic contexts and identify misalignment when it occurs", "Distinguish between operational control and strategic control and apply the four types of strategic control"]}'::jsonb
where slug = 'strategy-implementation'
  and lesson_id = (select id from lessons where slug = 'strategy' and course_id = (select id from courses where slug = 'strategic-management'));
